import React from "react";
import "./BatchAnalysis.css";

function BatchAnalysis({ onFileChange, onAnalyze, loading, results, selectedFile }) {
  const handleFileSelect = (e) => {
    if (e.target.files.length > 0) {
      onFileChange(e);
    }
  };

  const handleDownload = async () => {
    if (!results || !results.data) return;
    
    try {
      const response = await fetch('http://localhost:5000/api/download-batch', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ batch_data: results.data }),
      });

      if (!response.ok) {
        throw new Error('Download failed');
      }

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      a.download = `churn_analysis_${new Date().toISOString().split('T')[0]}.csv`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
    } catch (error) {
      console.error('Error downloading results:', error);
      alert('Download failed. Please try again.');
    }
  };

  const renderResults = () => {
    if (!results) return null;

    const totalRecords = results.summary?.total_customers || results.total_records || 0;
    const churnCount = results.summary?.high_risk_count || results.churn_count || 0;
    const churnRate = results.summary?.high_risk_percentage ? results.summary.high_risk_percentage / 100 : results.churn_rate || 0;

    return (
      <div className="batch-results">
        <h3>📊 Batch Analysis Results</h3>
        
        <div className="batch-stats">
          <div className="stat-card">
            <span className="stat-value">{totalRecords}</span>
            <span className="stat-label">Total Processed</span>
          </div>
          
          <div className="stat-card">
            <span className="stat-value">{churnCount}</span>
            <span className="stat-label">Churn Predictions</span>
          </div>
          
          <div className="stat-card">
            <span className="stat-value">
              {(churnRate * 100).toFixed(1)}%
            </span>
            <span className="stat-label">Churn Rate</span>
          </div>

          {results.summary?.total_potential_loss && (
            <div className="stat-card">
              <span className="stat-value">
                ₹{(results.summary.total_potential_loss).toFixed(0)}
              </span>
              <span className="stat-label">Potential Loss</span>
            </div>
          )}
        </div>

        {results.data && (
          <div className="download-section">
            <button onClick={handleDownload} className="export-btn primary">
              <span className="btn-icon">📥</span>
              Download Detailed Results
            </button>
          </div>
        )}

        <details className="raw-data">
          <summary>View Complete Results</summary>
          <pre>{JSON.stringify(results, null, 2)}</pre>
        </details>
      </div>
    );
  };

  return (
    <div className="batch-analysis">
      <div className="analysis-container">
        <div className="section-card">
          <div className="file-upload-area">
            <input
              type="file"
              accept=".csv"
              onChange={handleFileSelect}
              className="file-input"
              id="batch-file"
            />
            <label htmlFor="batch-file" className="file-label">
              <span className="btn-icon">📎</span>
              Choose CSV File
            </label>
            
            {selectedFile && (
              <div className="file-info">
                <span className="file-success">✅</span>
                <div className="file-details">
                  <strong>{selectedFile.name}</strong>
                  <span>{(selectedFile.size / 1024).toFixed(1)} KB</span>
                </div>
              </div>
            )}
            
            <div className="file-requirements">
              <p><small>Required format: CSV with customer features matching individual analysis fields</small></p>
            </div>
          </div>

          <div className="action-buttons-bottom">
            <button 
              className="action-btn primary" 
              onClick={onAnalyze} 
              disabled={loading || !selectedFile}
            >
              {loading ? (
                <>
                  <div className="spinner"></div>
                  Processing Batch...
                </>
              ) : (
                <>
                  <span className="btn-icon">🚀</span>
                  Analyze Batch
                </>
              )}
            </button>
          </div>
        </div>

        {renderResults()}
      </div>
    </div>
  );
}

export default BatchAnalysis;
